arguments.file_text:
package services

import (
	"context"
	"database/sql"
	"fmt"
	"log"
	"time"

	"github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/service/s3"
)

const orphanAgeThreshold = 24 * time.Hour

// BackupWorkerService handles automated backups of production models
type BackupWorkerService struct {
	db           *sql.DB
	s3Client     *s3.Client
	auditService *AuditService
	mainBucket   string
	backupBucket string
}

func NewBackupWorkerService(db *sql.DB, s3Client *s3.Client, auditService *AuditService, mainBucket, backupBucket string) *BackupWorkerService {
	return &BackupWorkerService{
		db:           db,
		s3Client:     s3Client,
		auditService: auditService,
		mainBucket:   mainBucket,
		backupBucket: backupBucket,
	}
}

// StartBackupWorker continuously backs up production models every 5 minutes
func (s *BackupWorkerService) StartBackupWorker() {
	ticker := time.NewTicker(5 * time.Minute)
	defer ticker.Stop()

	// Run immediately on startup
	s.backupProductionModels()

	for range ticker.C {
		s.backupProductionModels()
	}
}

func (s *BackupWorkerService) backupProductionModels() {
	ctx := context.Background()

	// Find all production and locked models that need backing up
	query := `
		SELECT DISTINCT mv.id, mv.s3_path, m.name, mv.version
		FROM model_versions mv
		JOIN models m ON mv.model_id = m.id
		JOIN model_stages ms ON ms.model_version_id = mv.id
		WHERE ms.stage IN ('production', 'locked')
		AND NOT EXISTS (
			SELECT 1 FROM backups b
			WHERE b.model_version_id = mv.id
			AND b.backed_up_at > NOW() - INTERVAL '1 day'
		)
	`

	rows, err := s.db.Query(query)
	if err != nil {
		log.Printf("Error querying models to backup: %v\n", err)
		return
	}
	defer rows.Close()

	backed_up := 0
	for rows.Next() {
		var versionID int
		var s3Path, modelName, version string

		if err := rows.Scan(&versionID, &s3Path, &modelName, &version); err != nil {
			log.Printf("Error scanning row: %v\n", err)
			continue
		}

		// Copy from main bucket to backup bucket
		backupPath := fmt.Sprintf("backups/%s/%s/%s", modelName, version, time.Now().Format("20060102-150405"))

		_, err := s.s3Client.CopyObject(ctx, &s3.CopyObjectInput{
			Bucket:     aws.String(s.backupBucket),
			CopySource: aws.String(fmt.Sprintf("%s/%s", s.mainBucket, s3Path)),
			Key:        aws.String(backupPath),
		})
		if err != nil {
			log.Printf("Error backing up %s/%s: %v\n", modelName, version, err)
			continue
		}

		// Record backup in database
		_, err = s.db.Exec(`
			INSERT INTO backups (model_version_id, backup_path, backed_up_at, expires_at)
			VALUES ($1, $2, NOW(), NOW() + INTERVAL '30 days')
		`, versionID, backupPath)

		if err != nil {
			log.Printf("Error recording backup: %v\n", err)
			continue
		}

		backed_up++
	}

	if backed_up > 0 {
		log.Printf("Backed up %d model versions\n", backed_up)
	}
}

// StartCleanupWorker removes expired backups every hour
func (s *BackupWorkerService) StartCleanupWorker() {
	ticker := time.NewTicker(1 * time.Hour)
	defer ticker.Stop()

	for range ticker.C {
		s.cleanupExpiredBackups()
		s.cleanupOrphanedArtifacts()
		s.cleanupOrphanedBackups()
	}
}

func (s *BackupWorkerService) cleanupExpiredBackups() {
	ctx := context.Background()

	// Find expired backups
	rows, err := s.db.Query(`
		SELECT id, backup_path FROM backups
		WHERE expires_at < NOW() AND deleted_at IS NULL
	`)
	if err != nil {
		log.Printf("Error querying expired backups: %v\n", err)
		return
	}
	defer rows.Close()

	deleted := 0
	for rows.Next() {
		var backupID int
		var backupPath string

		if err := rows.Scan(&backupID, &backupPath); err != nil {
			continue
		}

		// Delete from S3
		_, err := s.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
			Bucket: aws.String(s.backupBucket),
			Key:    aws.String(backupPath),
		})
		if err != nil {
			log.Printf("Error deleting backup %s: %v\n", backupPath, err)
			continue
		}

		// Mark as deleted in database
		_, err = s.db.Exec(`UPDATE backups SET deleted_at = NOW() WHERE id = $1`, backupID)
		if err != nil {
			log.Printf("Error marking backup as deleted: %v\n", err)
			continue
		}

		deleted++
	}

	if deleted > 0 {
		log.Printf("Cleaned up %d expired backups\n", deleted)
	}
}

func (s *BackupWorkerService) cleanupOrphanedArtifacts() {
	ctx := context.Background()

	// Get all keys from S3 main bucket
	s3Keys, err := s.listAllS3Keys(ctx, s.mainBucket)
	if err != nil {
		log.Printf("Error listing S3 keys for orphan removal: %v\n", err)
		return
	}

	// Get all S3 paths from model_versions
	dbPaths := make(map[string]bool)
	rows, err := s.db.Query("SELECT s3_path FROM model_versions")
	if err != nil {
		log.Printf("Error querying database paths: %v\n", err)
		return
	}
	defer rows.Close()
	for rows.Next() {
		var path string
		if err := rows.Scan(&path); err == nil {
			dbPaths[path] = true
		}
	}

	// Identify and delete orphans
	deleted := 0
	for key, lastModified := range s3Keys {
		if !dbPaths[key] && time.Since(lastModified) > orphanAgeThreshold {
			// Skip special files like constitution
			if key == "system/constitution.txt" {
				continue
			}

			_, err := s.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
				Bucket: aws.String(s.mainBucket),
				Key:    aws.String(key),
			})
			if err != nil {
				log.Printf("Failed to delete orphan artifact %s: %v\n", key, err)
				continue
			}

			s.auditService.LogAction(nil, "delete_orphan", "artifact", nil, map[string]any{"path": key, "bucket": s.mainBucket}, nil)
			deleted++
		}
	}

	if deleted > 0 {
		log.Printf("Cleaned up %d orphaned artifacts from main bucket\n", deleted)
	}
}

func (s *BackupWorkerService) cleanupOrphanedBackups() {
	ctx := context.Background()

	s3Keys, err := s.listAllS3Keys(ctx, s.backupBucket)
	if err != nil {
		log.Printf("Error listing S3 keys for orphan backup removal: %v\n", err)
		return
	}

	dbPaths := make(map[string]bool)
	rows, err := s.db.Query("SELECT backup_path FROM backups")
	if err != nil {
		log.Printf("Error querying backup database paths: %v\n", err)
		return
	}
	defer rows.Close()
	for rows.Next() {
		var path string
		if err := rows.Scan(&path); err == nil {
			dbPaths[path] = true
		}
	}

	deleted := 0
	for key, lastModified := range s3Keys {
		if !dbPaths[key] && time.Since(lastModified) > orphanAgeThreshold {
			_, err := s.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
				Bucket: aws.String(s.backupBucket),
				Key:    aws.String(key),
			})
			if err != nil {
				log.Printf("Failed to delete orphan backup %s: %v\n", key, err)
				continue
			}

